def get_home_directory():
    """Get the user's home directory cross-platform."""
    return str(Path.home())


def get_config_directory():
    """Get the configuration directory path."""
    return os.path.join(get_home_directory(), CONFIG_DIR_NAME)


def get_resources_directory():
    """Get the resources directory path."""
    return os.path.join(get_config_directory(), RESOURCES_DIR_NAME)


def create_configuration_directories():
    """Create all necessary configuration directories."""
    config_dir = get_config_directory()
    resources_dir = get_resources_directory()

    directories = [
        config_dir,
        resources_dir,
        os.path.join(config_dir, "logs"),
        os.path.join(config_dir, "cache"),
        os.path.join(config_dir, "data"),
        os.path.join(config_dir, "plugins"),
        os.path.join(config_dir, "templates"),
    ]

    for directory in directories:
        os.makedirs(directory, exist_ok=True)
        print(f"[internal_lib] Created directory: {directory}")

    return config_dir, resources_dir


def create_default_config(config_dir):
    """Create default configuration file if it doesn't exist."""
    config_path = os.path.join(config_dir, "config.json")

    if not os.path.exists(config_path):
        config = DEFAULT_CONFIG.copy()
        config["paths"] = {
            "home": get_home_directory(),
            "config": config_dir,
            "resources": get_resources_directory(),
            "logs": os.path.join(config_dir, "logs"),
            "cache": os.path.join(config_dir, "cache"),
        }

        with open(config_path, "w") as f:
            json.dump(config, f, indent=4)
        print(f"[internal_lib] Created default config: {config_path}")
    else:
        print(f"[internal_lib] Config already exists: {config_path} (skipping)")

    return config_path


def download_resources(resources_dir):
    """Download additional resources needed by the library."""
    downloaded = []
    failed = []

    for filename, url in ADDITIONAL_RESOURCES.items():
        dest_path = os.path.join(resources_dir, filename)

        if os.path.exists(dest_path):
            print(f"[internal_lib] Resource already exists: {filename} (skipping)")
            downloaded.append(filename)
            continue

        try:
            print(f"[internal_lib] Downloading: {filename} from {url}")
            urllib.request.urlretrieve(url, dest_path)
            print(f"[internal_lib] Successfully downloaded: {filename}")
            downloaded.append(filename)
        except Exception as e:
            print(f"[internal_lib] WARNING: Failed to download {filename}: {e}")
            print(f"[internal_lib] You may need to manually download this resource later.")
            failed.append((filename, str(e)))

            # Create a placeholder file with error info
            placeholder_path = dest_path + ".missing"
            with open(placeholder_path, "w") as f:
                f.write(f"Failed to download: {url}\nError: {e}\n")

    return downloaded, failed


def setup_environment_variables(config_dir):
    """Set up environment variables and create an env file."""
    env_vars = DEFAULT_ENV_VARS.copy()
    env_vars["INTERNAL_LIB_HOME"] = get_home_directory()
    env_vars["INTERNAL_LIB_CONFIG_DIR"] = config_dir
    env_vars["INTERNAL_LIB_RESOURCES_DIR"] = get_resources_directory()

    # Write .env file
    env_file_path = os.path.join(config_dir, ENV_FILE_NAME)
    with open(env_file_path, "w") as f:
        f.write(f"# Internal Library Environment Variables\n")
        f.write(f"# Generated during installation of {PACKAGE_NAME} v{VERSION}\n")
        f.write(f"# Modify these values as needed for your environment\n\n")

        for key, value in sorted(env_vars.items()):
            f.write(f"{key}={value}\n")

    print(f"[internal_lib] Created environment file: {env_file_path}")

    # Write a shell-sourceable script
    shell_env_path = os.path.join(config_dir, "activate_env.sh")
    with open(shell_env_path, "w") as f:
        f.write("#!/bin/bash\n")
        f.write(f"# Source this file to set up internal_lib environment variables\n")
        f.write(f"# Usage: source {shell_env_path}\n\n")
        for key, value in sorted(env_vars.items()):
            f.write(f'export {key}="{value}"\n')
        f.write('\necho "internal_lib environment variables loaded."\n')

    os.chmod(shell_env_path, 0o755)
    print(f"[internal_lib] Created shell env script: {shell_env_path}")

    # Write a PowerShell script for Windows users
    ps_env_path = os.path.join(config_dir, "activate_env.ps1")
    with open(ps_env_path, "w") as f:
        f.write(f"# PowerShell script to set up internal_lib environment variables\n")
        f.write(f"# Usage: . {ps_env_path}\n\n")
        for key, value in sorted(env_vars.items()):
            f.write(f'$env:{key} = "{value}"\n')
        f.write('\nWrite-Host "internal_lib environment variables loaded."\n')

    print(f"[internal_lib] Created PowerShell env script: {ps_env_path}")

    # Set environment variables for the current process
    for key, value in env_vars.items():
        os.environ[key] = value

    return env_vars, env_file_path


def create_gitignore(config_dir):
    """Create a .gitignore file in the config directory."""
